import{_ as a,o as i,c as n,ag as t}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"Compiler Pipeline","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/compiler-pipeline.md","filePath":"architecture/compiler-pipeline.md"}'),s={name:"architecture/compiler-pipeline.md"};function r(l,e,o,p,c,d){return i(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="compiler-pipeline" tabindex="-1">Compiler Pipeline <a class="header-anchor" href="#compiler-pipeline" aria-label="Permalink to &quot;Compiler Pipeline&quot;">​</a></h1><p>This page describes the main compilation flow from source text to native code or SIR-backed execution.</p><h2 id="end-to-end-flow" tabindex="-1">End-to-End Flow <a class="header-anchor" href="#end-to-end-flow" aria-label="Permalink to &quot;End-to-End Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source (.vx)</span></span>
<span class="line"><span>  -&gt; lexer</span></span>
<span class="line"><span>  -&gt; parser / syntax tree</span></span>
<span class="line"><span>  -&gt; HIR lowering</span></span>
<span class="line"><span>  -&gt; type inference + borrow analysis + semantic checks</span></span>
<span class="line"><span>  -&gt; codegen selection</span></span>
<span class="line"><span>       -&gt; LLVM/native path</span></span>
<span class="line"><span>       -&gt; SIR graph path</span></span>
<span class="line"><span>  -&gt; link / JIT / subprocess execution</span></span></code></pre></div><h2 id="front-end-stages" tabindex="-1">Front-End Stages <a class="header-anchor" href="#front-end-stages" aria-label="Permalink to &quot;Front-End Stages&quot;">​</a></h2><h3 id="lexer" tabindex="-1">Lexer <a class="header-anchor" href="#lexer" aria-label="Permalink to &quot;Lexer&quot;">​</a></h3><p><code>vex-lexer</code> tokenizes source text.</p><h3 id="parser" tabindex="-1">Parser <a class="header-anchor" href="#parser" aria-label="Permalink to &quot;Parser&quot;">​</a></h3><p><code>vex-parser</code> constructs the syntax tree and keeps enough recovery behavior for diagnostics and tooling.</p><h3 id="syntax-layer" tabindex="-1">Syntax Layer <a class="header-anchor" href="#syntax-layer" aria-label="Permalink to &quot;Syntax Layer&quot;">​</a></h3><p><code>vex-syntax</code> defines the syntax node model used by the parser and later lowering passes.</p><h2 id="hir-and-semantic-analysis" tabindex="-1">HIR and Semantic Analysis <a class="header-anchor" href="#hir-and-semantic-analysis" aria-label="Permalink to &quot;HIR and Semantic Analysis&quot;">​</a></h2><p><code>vex-hir</code> is where syntax becomes semantically meaningful program structure.</p><p>Key responsibilities include:</p><ul><li>name resolution</li><li>type inference</li><li>pattern lowering</li><li>contract-related checks</li><li>borrow and move analysis</li><li>enum, <code>Option</code>, and <code>Result</code> behavior</li></ul><h2 id="memory-safety-analysis" tabindex="-1">Memory-Safety Analysis <a class="header-anchor" href="#memory-safety-analysis" aria-label="Permalink to &quot;Memory-Safety Analysis&quot;">​</a></h2><p>The repository describes the borrow system as a multi-phase analysis model. The high-level responsibilities are:</p><ol><li>immutability and <code>let</code> vs <code>let!</code> enforcement</li><li>move tracking</li><li>borrow rule validation</li><li>lifetime-oriented validation</li></ol><p>This is the part of the compiler that enforces the memory model documented in the guide.</p><h2 id="two-main-lowering-paths" tabindex="-1">Two Main Lowering Paths <a class="header-anchor" href="#two-main-lowering-paths" aria-label="Permalink to &quot;Two Main Lowering Paths&quot;">​</a></h2><h3 id="native-llvm-path" tabindex="-1">Native LLVM Path <a class="header-anchor" href="#native-llvm-path" aria-label="Permalink to &quot;Native LLVM Path&quot;">​</a></h3><p><code>vex-compiler</code> lowers checked HIR into LLVM IR and then into object code, linked executables, or JIT-executed code.</p><p>This path is the default for ordinary systems code.</p><h3 id="sir-path" tabindex="-1">SIR Path <a class="header-anchor" href="#sir-path" aria-label="Permalink to &quot;SIR Path&quot;">​</a></h3><p>When the program shape is suitable for data-parallel lowering, Vex can form SIR graphs that later target SIMD and selected accelerator backends.</p><p>This path is the basis for:</p><ul><li>vector-style arithmetic</li><li>tensor and mask operations</li><li>fusion and graph rewrites</li><li>backend-specific kernel generation</li></ul><h2 id="driver-layer" tabindex="-1">Driver Layer <a class="header-anchor" href="#driver-layer" aria-label="Permalink to &quot;Driver Layer&quot;">​</a></h2><p>The user usually interacts with the compiler through <code>vex-cli</code>, which wraps compilation, linking, JIT/no-JIT execution, and test discovery.</p><p>That means the operational pipeline is often:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vex run / vex compile / vex test</span></span>
<span class="line"><span>  -&gt; compiler driver</span></span>
<span class="line"><span>  -&gt; runtime + linker integration</span></span>
<span class="line"><span>  -&gt; execution or test reporting</span></span></code></pre></div><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="/docs/architecture/sir-and-backends">SIR &amp; Backends</a></li><li><a href="/docs/architecture/runtime-and-tooling">Runtime &amp; Tooling</a></li><li><a href="/docs/references/vex-cli-reference">CLI Reference</a></li></ul>`,33)])])}const u=a(s,[["render",r]]);export{m as __pageData,u as default};
